import{_ as a,o as e,c as r,a2 as l}from"./chunks/framework.BQ1gajhD.js";const b=JSON.parse('{"title":"团城","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/beihai/tuancheng.md","filePath":"landmarks/beihai/tuancheng.md","lastUpdated":1784720050000}'),n={name:"landmarks/beihai/tuancheng.md"};function o(s,t,i,g,d,h){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="团城" tabindex="-1">团城 <a class="header-anchor" href="#团城" aria-label="Permalink to &quot;团城&quot;">​</a></h1><p><img src="https://plus.unsplash.com/premium_photo-1691086684103-a2d0319d79ac?w=1200&amp;q=80" alt="团城"></p><blockquote><p>一座圆形的小城，城中藏着缅甸白玉佛与三吨重的元代酒器——从忽必烈的御宴到腌菜的瓦缸，渎山大玉海的身世，比任何小说都传奇。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><strong>团城</strong>位于北海公园南门（正门）外，是一座<strong>圆形的砖砌城台</strong>，四面围以城墙、上筑殿宇，形如一座袖珍城池，故称&quot;团城&quot;。它与琼华岛隔水相望，是北海的&quot;前庭&quot;，也是从南门入园的第一站。</p><p>登上团城，最负盛名的是<strong>承光殿</strong>内供奉的<strong>白玉佛</strong>，以及殿侧玉瓮亭中的<strong>渎山大玉海</strong>——一件用整块墨玉雕成、重达<strong>3.5吨</strong>的元代巨型酒器。这两件国宝，一静一动、一白一墨，共同讲述着跨越数百年的王朝往事。</p><p>团城虽小，却是一座&quot;麻雀虽小、五脏俱全&quot;的城池：有城墙、有城楼、有殿宇、有古木，自成一统。站在城上俯瞰，南可望中南海的碧波，北可眺琼华岛的白塔，是连接南北两景的枢纽，也是从南门入园时最先撞入眼帘的一幅古典画卷。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">辽金</td><td style="text-align:left;">始建，为太液池中的圆形小岛&quot;圆坻&quot;</td></tr><tr><td style="text-align:left;">元代</td><td style="text-align:left;">忽必烈建仪天殿于岛上，渎山大玉海曾陈于此</td></tr><tr><td style="text-align:left;">明代</td><td style="text-align:left;">填岛为圆形城台，筑城墙，名&quot;团城&quot;</td></tr><tr><td style="text-align:left;">清乾隆年间</td><td style="text-align:left;">赎回渎山大玉海，建玉瓮亭供奉，重修承光殿</td></tr><tr><td style="text-align:left;">1900年</td><td style="text-align:left;">遭八国联军劫掠，白玉佛身留刀痕</td></tr><tr><td style="text-align:left;">当代</td><td style="text-align:left;">列为全国重点文物保护单位</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>形制</strong></td><td style="text-align:left;">圆形砖砌城台，四面围以城墙</td></tr><tr><td style="text-align:left;"><strong>位置</strong></td><td style="text-align:left;">北海公园南门外，与琼华岛隔水相望</td></tr><tr><td style="text-align:left;"><strong>主殿</strong></td><td style="text-align:left;">承光殿（歇山式大殿）</td></tr><tr><td style="text-align:left;"><strong>白玉佛</strong></td><td style="text-align:left;">缅甸进贡的整块白玉雕成，通体莹洁</td></tr><tr><td style="text-align:left;"><strong>渎山大玉海</strong></td><td style="text-align:left;">元代整块墨玉雕成的巨型酒器，重约3.5吨</td></tr><tr><td style="text-align:left;"><strong>著名古树</strong></td><td style="text-align:left;">遮荫侯（白皮松）、白袍将军等，多为数百年古木</td></tr></tbody></table><h3 id="承光殿与白玉佛" tabindex="-1">承光殿与白玉佛 <a class="header-anchor" href="#承光殿与白玉佛" aria-label="Permalink to &quot;承光殿与白玉佛&quot;">​</a></h3><p><strong>承光殿</strong>是团城的主体建筑，为歇山式大殿，殿内供奉一尊<strong>白玉佛</strong>。这尊佛像由<strong>缅甸进贡的整块白玉</strong>雕琢而成，通体莹洁温润，是清代中外文化交流的珍贵见证。令人唏嘘的是，佛像上至今仍留有<strong>八国联军侵华时砍凿的刀痕</strong>——1900年团城遭侵略者劫掠，白玉佛身被砍伤，这道伤痕成为近代屈辱史的无声见证。</p><h3 id="渎山大玉海" tabindex="-1">渎山大玉海 <a class="header-anchor" href="#渎山大玉海" aria-label="Permalink to &quot;渎山大玉海&quot;">​</a></h3><p>殿侧玉瓮亭中珍藏的<strong>渎山大玉海</strong>，是团城的镇城之宝。它由<strong>一整块墨玉</strong>雕琢而成，体量巨大，重约<strong>3.5吨</strong>，是<strong>元代</strong>忽必烈时期制成的皇家<strong>巨型酒器</strong>。玉瓮周身还雕有海浪、蛟龙、海马等纹饰，线条豪放，尽显蒙元帝国的雄浑气魄。然而玉瓮的身世几经沉浮：<strong>明朝末年</strong>竟沦落到<strong>道士手中做了腌菜的瓦缸</strong>，盛放咸菜数百年；直到<strong>清乾隆年间</strong>，乾隆帝得知下落，不惜重金<strong>赎回</strong>，建玉瓮亭保护，并亲题御诗。</p><h3 id="遮荫侯与古木" tabindex="-1">遮荫侯与古木 <a class="header-anchor" href="#遮荫侯与古木" aria-label="Permalink to &quot;遮荫侯与古木&quot;">​</a></h3><p>团城之上古木参天，其中最著名的是乾隆御封的**&quot;遮荫侯&quot;<strong>——一株苍劲的</strong>白皮松**，树龄数百年，枝干虬曲、浓荫如盖，相传乾隆曾在树下纳凉，感其荫蔽，遂封之为&quot;遮荫侯&quot;。此外还有被封为&quot;白袍将军&quot;的白皮松、&quot;探海侯&quot;的古油松等古树名木，与城台殿宇相映，为团城平添一份古朴幽深。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="忽必烈的御宴酒器" tabindex="-1">忽必烈的御宴酒器 <a class="header-anchor" href="#忽必烈的御宴酒器" aria-label="Permalink to &quot;忽必烈的御宴酒器&quot;">​</a></h3><p>相传元世祖忽必烈定都大都后，常于琼华岛广寒殿、团城一带大宴群臣。渎山大玉瓮便是这御宴之上的核心酒器——以整块墨玉雕成，可盛酒数石，群臣以勺取饮，觥筹交错间尽显蒙元帝国的恢宏气度。一只酒器能做成三吨半的体量，古今中外罕见，足见皇家气派之奢。</p><h3 id="从腌菜缸到国宝" tabindex="-1">从腌菜缸到国宝 <a class="header-anchor" href="#从腌菜缸到国宝" aria-label="Permalink to &quot;从腌菜缸到国宝&quot;">​</a></h3><p>渎山大玉海最动人的，是它&quot;沉沦—重生&quot;的经历。元亡之后，这件重器几经辗转，竟流落到西华门外一座道观中，被道士当作腌菜的大缸，日复一日盛着咸菜，蒙尘数百年。直到清乾隆年间，一位有识之士辨认出它非凡的来历，上报朝廷，乾隆帝遂以重金赎回，郑重安置于团城，建亭供奉。从御宴酒器到腌菜瓦缸，再到镇城国宝——渎山大玉海用自身的命运，写就了一部浓缩的兴衰史。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>渎山大玉海</strong>：亲睹这件3.5吨的元代整块墨玉酒器，细看其周身海浪蛟龙的豪放纹饰，想象它从忽必烈御宴到腌菜瓦缸的传奇身世。</li><li><strong>白玉佛</strong>：瞻仰承光殿内缅甸白玉雕成的佛像，留意八国联军留下的刀痕，感受历史的厚重与沧桑。</li><li><strong>遮荫侯古松</strong>：寻访乾隆御封的白皮松，在数百年古木下感受团城的幽静与帝王的雅趣。</li><li><strong>圆形城台</strong>：环城墙漫步，体会这座&quot;袖珍城池&quot;独特的圆形格局。</li><li><strong>隔水望白塔</strong>：在团城之上远眺琼华岛白塔，是南门入园时的第一幅经典画面。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>玉瓮亭特写</strong>：近距离拍摄渎山大玉海的墨玉质感与雕纹，凸显其厚重体量。</li><li><strong>城上望白塔</strong>：团城城台与远处白塔同框，是连接南北两景的经典构图。</li><li><strong>古松与红墙</strong>：遮荫侯古松与团城红墙相映，苍劲古朴，极具画意。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li><strong>南门首站</strong>：团城位于南门外，从南门入园时是理想的第一站，可先游团城再过桥登琼华岛。</li><li><strong>联票入园</strong>：联票（20元）已含团城与琼华岛，建议购联票，单买门票不含团城。</li><li><strong>细看玉瓮</strong>：渎山大玉海值得驻足细看，其雕工、体量与传奇身世，是团城的精华所在。</li><li><strong>留意刀痕</strong>：观白玉佛时留意佛像上的砍凿痕迹，那是近代史留下的无声见证。</li><li><strong>联游琼岛</strong>：团城与<a href="/beijing-travel-guide/landmarks/beihai/baita.html">琼华岛（白塔）</a>隔桥相连，两处安排在一起游览最为顺路。</li><li><strong>联游北岸</strong>：游完团城与琼岛，可沿湖至北岸游<a href="/beijing-travel-guide/landmarks/beihai/jiulongbi.html">九龙壁</a>、<a href="/beijing-travel-guide/landmarks/beihai/wulongting.html">五龙亭</a>。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：团城和北海公园是什么关系？</strong></p><p>团城位于北海公园南门外，原是太液池中的圆形小岛，明代填岛筑城而成。如今它与北海公园统一开放，购联票（20元）即可同时游览团城与琼华岛。</p><p><strong>Q：渎山大玉海到底有多重？是做什么用的？</strong></p><p>渎山大玉海由一整块墨玉雕成，重约3.5吨，是元代忽必烈时期的皇家巨型酒器，用以盛酒大宴群臣。它是现存最大的古代玉雕器皿之一，堪称国宝。</p><p><strong>Q：白玉佛上的刀痕是怎么回事？</strong></p><p>1900年八国联军侵华时劫掠团城，砍伤了殿内的白玉佛，佛像上至今留有那道刀痕。它没有被修复抹去，而是作为近代屈辱史的见证保留至今。</p><hr><p><strong>📍 位置</strong>：北海公园南门外，与琼华岛隔水相望 <strong>⏱️ 建议游览</strong>：40-60分钟 <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/beihai/baita.html">白塔与琼华岛</a>（过永安桥可达） <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/beihai/jiulongbi.html">九龙壁</a>、<a href="/beijing-travel-guide/landmarks/beihai/wulongting.html">五龙亭</a>（环湖北岸） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/beihai/">北海公园概览</a></p>',37)])])}const f=a(n,[["render",o]]);export{b as __pageData,f as default};
